mapper.select:
select n.id, n.title, to_char(n.addtime,'yyyy-mm-dd') as addtime, t.real_name as fbr, n.type from newstb n left join teacher t on n.fbr=t.id
where type = #{type, jdbcType=INTEGER}
order by n.addtime desc

WITH eids AS ( SELECT e.id AS eid FROM examinfo e WHERE e.teacherid = #{tid}
UNION SELECT tq.eid FROM teacher_question tq WHERE tq.tid = #{tid}
UNION SELECT tp.eid FROM teacher_paper tp WHERE tp.tid = #{tid} ), perm_flag AS ( SELECT tp.eid, MAX(CASE WHEN tp.pid = '35' THEN 1 ELSE 0 END) AS can_first_verify FROM teacher_paper tp WHERE tp.tid = #{tid} GROUP BY tp.eid ) SELECT COUNT(*) AS num FROM eids x JOIN examinfo e ON e.id = x.eid LEFT JOIN perm_flag pf ON pf.eid = e.id WHERE e.state NOT IN (6, -1, -2) AND e.mobile IN (0, 2) AND e.aorb = 0 AND ( (e.state = 0 AND e.teacherid = #{tid}) OR (e.state = 1 AND (e.teacherid = #{tid} OR NVL(pf.can_first_verify,0) = 1)) OR (e.state IN (2, 7, 8)) OR (e.state = 3 AND e.teacherid = #{tid}) )
